import React, { useEffect, useMemo, useState } from "react";
import { api } from "./api";
import { BarChart3, CheckCircle2, ChevronLeft, ChevronRight, CircleX, Clock, Copy, Eye, FlaskConical, History, PauseCircle, Pencil, Plus, RefreshCw, Search, Trash2, Trophy, X } from "lucide-react";

const primary = "inline-flex items-center justify-center gap-2 rounded-xl bg-[#7A1420] px-4 py-2.5 text-sm font-medium text-white hover:bg-[#611018] disabled:opacity-50";
const secondary = "inline-flex items-center justify-center gap-2 rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-600 hover:bg-slate-50 disabled:opacity-40 dark:border-slate-600 dark:bg-slate-800 dark:text-slate-200";
const input = "mt-1 w-full rounded-xl border border-slate-200 bg-white px-3 py-2.5 text-sm outline-none focus:border-[#7A1420] dark:border-slate-600 dark:bg-slate-800";
const vazioReceita = { produtoFinalId:"", nome:"", categoria:"", descricao:"", fotoUrl:"", rendimento:"", unidadeRendimento:"porção", tempoPreparoMinutos:"", setorPadrao:"", instrucoesProducao:"", equipamentos:"", responsavelPadrao:"", etapas:[], modoPreparo:"", observacoes:"", ativo:true, itens:[] };
const vazioProducao = () => ({ receitaId:"", funcionarioId:"", quantidadeProduzida:"", unidade:"porção", dataProducao:new Date().toISOString().slice(0,10), horaInicio:"", horaFim:"", lote:"", validade:"", status:"EM_ANDAMENTO", setor:"", quantidadePerdida:"", motivoPerda:"", observacoes:"" });
const n = valor => Number(valor || 0);
const money = valor => n(valor).toLocaleString("pt-BR", { style:"currency", currency:"BRL" });
const date = valor => valor ? new Date(valor).toLocaleDateString("pt-BR") : "—";
const dateTime = valor => valor ? new Date(valor).toLocaleString("pt-BR", { dateStyle:"short", timeStyle:"short" }) : "—";
const toIsoDate = valor => valor ? new Date(`${valor}T12:00:00`).toISOString() : undefined;
const toIsoDateTime = valor => valor ? new Date(valor).toISOString() : undefined;
const toDateTimeInput = valor => valor ? new Date(valor).toISOString().slice(0,16) : "";
const falha = e => e?.message || "Não foi possível concluir a operação.";

function Card({ children, className="" }) { return <section className={`rounded-2xl border border-slate-200 bg-white shadow-sm dark:border-slate-700 dark:bg-slate-800/60 ${className}`}>{children}</section>; }
function Modal({ titulo, onClose, children }) { return <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/60 p-4"><section className="max-h-[92vh] w-full max-w-5xl overflow-y-auto rounded-2xl bg-white p-5 shadow-2xl dark:bg-slate-800"><div className="mb-5 flex items-center justify-between"><h3 className="text-lg font-semibold text-slate-900 dark:text-white">{titulo}</h3><button onClick={onClose} className="rounded-lg p-1 text-slate-400 hover:bg-slate-100"><X size={19} /></button></div>{children}</section></div>; }
function Status({ status, ativo }) { const valor=status || (ativo ? "ATIVO" : "INATIVO"); const texto={ATIVO:"Ativa",INATIVO:"Inativa",EM_ANDAMENTO:"Em andamento",PAUSADA:"Pausada",CONCLUIDA:"Concluída",CANCELADA:"Cancelada"}[valor]; const cor={ATIVO:"bg-emerald-50 text-emerald-700",INATIVO:"bg-slate-100 text-slate-600",EM_ANDAMENTO:"bg-amber-50 text-amber-700",PAUSADA:"bg-sky-50 text-sky-700",CONCLUIDA:"bg-emerald-50 text-emerald-700",CANCELADA:"bg-rose-50 text-rose-700"}[valor]; return <span className={`inline-flex rounded-full px-2 py-0.5 text-[11px] font-semibold ${cor}`}>{texto}</span>; }
function Metric({ label, value, hint, Icon }) { return <Card className="p-4"><div className="flex items-start justify-between gap-3"><div><div className="text-xs font-medium uppercase tracking-wide text-slate-400">{label}</div><div className="mt-2 text-2xl font-semibold text-slate-900 dark:text-white">{value}</div><div className="mt-1 text-xs text-slate-500">{hint}</div></div><Icon size={19} className="text-[#7A1420] dark:text-red-300" /></div></Card>; }
function Periodo({ filtros, mudar }) { return <div className="flex flex-wrap items-end gap-2"><label className="text-xs text-slate-500">Período<select value={filtros.periodo || "todos"} onChange={e=>mudar("periodo",e.target.value)} className={input}><option value="todos">Todo o período</option><option value="hoje">Hoje</option><option value="semana">Semana atual</option><option value="mes">Mês atual</option><option value="personalizado">Personalizado</option></select></label>{filtros.periodo === "personalizado" && <><label className="text-xs text-slate-500">De<input type="date" value={filtros.dataInicio || ""} onChange={e=>mudar("dataInicio",e.target.value)} className={input} /></label><label className="text-xs text-slate-500">Até<input type="date" value={filtros.dataFim || ""} onChange={e=>mudar("dataFim",e.target.value)} className={input} /></label></>}</div>; }
function Paginacao({ meta, mudar }) { if (!meta) return null; return <div className="flex items-center justify-between border-t border-slate-100 px-4 py-3 text-xs text-slate-500 dark:border-slate-700"><span>{meta.total} registro(s) · página {meta.page} de {meta.pages}</span><div className="flex gap-2"><button disabled={meta.page<=1} onClick={()=>mudar(meta.page-1)} className={secondary}><ChevronLeft size={15}/>Anterior</button><button disabled={meta.page>=meta.pages} onClick={()=>mudar(meta.page+1)} className={secondary}>Próxima<ChevronRight size={15}/></button></div></div>; }

function ReceitaForm({ receita, insumos, onSalvar, salvando, historico=[] }) {
 const [form,setForm]=useState(()=>({ ...vazioReceita,...receita,rendimento:receita?.rendimento??"",tempoPreparoMinutos:receita?.tempoPreparoMinutos??"",itens:receita?.itens||[] }));
 const [novo,setNovo]=useState({insumoId:"",nome:"",quantidade:"",unidade:"",custoUnitario:""});
 const mudar=(k,v)=>setForm(a=>({...a,[k]:v}));
 const escolher=id=>{const item=insumos.find(i=>i.id===id);setNovo(a=>({...a,insumoId:id,nome:item?.nome||a.nome,unidade:item?.un||a.unidade,custoUnitario:item?.custo??a.custoUnitario}));};
 const escolherProdutoFinal=id=>{const item=insumos.find(i=>i.id===id);setForm(a=>({...a,produtoFinalId:id,unidadeRendimento:item?.un||a.unidadeRendimento}));};
 const adicionar=()=>{if(!novo.insumoId||!novo.nome.trim()||n(novo.quantidade)<=0||!novo.unidade.trim())return;setForm(a=>({...a,itens:[...a.itens,{...novo,quantidade:n(novo.quantidade),custoUnitario:novo.custoUnitario===""?undefined:n(novo.custoUnitario)}]}));setNovo({insumoId:"",nome:"",quantidade:"",unidade:"",custoUnitario:""});};
 const produtoFinal=insumos.find(i=>i.id===form.produtoFinalId);
 const custo=form.itens.reduce((t,i)=>t+n(i.quantidade)*n(i.custoUnitario),0);
 const enviar=e=>{e.preventDefault();if(!form.produtoFinalId||!form.itens.length)return;onSalvar({...form,rendimento:n(form.rendimento),tempoPreparoMinutos:form.tempoPreparoMinutos===""?undefined:Number(form.tempoPreparoMinutos),itens:form.itens.map(i=>({...i,quantidade:n(i.quantidade),custoUnitario:i.custoUnitario==null||i.custoUnitario===""?undefined:n(i.custoUnitario)}))});};
 return <form onSubmit={enviar} className="space-y-5">
  <Card className="p-5"><div className="mb-4"><h4 className="font-semibold">Dados da receita</h4><p className="text-xs text-slate-400">Identifica&ccedil;&atilde;o e orienta&ccedil;&otilde;es para o preparo.</p></div><div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3"><label className="text-xs text-slate-500">Nome da receita<input required value={form.nome} onChange={e=>mudar("nome",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Categoria<input value={form.categoria||""} onChange={e=>mudar("categoria",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Foto (URL opcional)<input type="url" value={form.fotoUrl||""} onChange={e=>mudar("fotoUrl",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Tempo estimado (min)<input type="number" min="0" value={form.tempoPreparoMinutos} onChange={e=>mudar("tempoPreparoMinutos",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Setor respons&aacute;vel pela produ&ccedil;&atilde;o<input value={form.setorPadrao||""} onChange={e=>mudar("setorPadrao",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Respons&aacute;vel padr&atilde;o<input value={form.responsavelPadrao||""} onChange={e=>mudar("responsavelPadrao",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Equipamentos<input value={form.equipamentos||""} onChange={e=>mudar("equipamentos",e.target.value)} placeholder="Forno, batedeira..." className={input}/></label><label className="col-span-full text-xs text-slate-500">Descri&ccedil;&atilde;o<textarea value={form.descricao||""} onChange={e=>mudar("descricao",e.target.value)} className={input+" min-h-20"}/></label><label className="col-span-full text-xs text-slate-500">Instru&ccedil;&otilde;es de produ&ccedil;&atilde;o<textarea value={form.instrucoesProducao||""} onChange={e=>mudar("instrucoesProducao",e.target.value)} className={input+" min-h-20"}/></label><label className="col-span-full text-xs text-slate-500">Etapas do preparo<textarea value={(form.etapas||[]).map(i=>typeof i === "string" ? i : i.nome).join("\n")} onChange={e=>mudar("etapas",e.target.value.split("\n").map(v=>v.trim()).filter(Boolean).map((nome,ordem)=>({nome,ordem:ordem+1})))} placeholder="Uma etapa por linha" className={input+" min-h-20"}/></label><label className="col-span-full text-xs text-slate-500">Modo de preparo<textarea value={form.modoPreparo||""} onChange={e=>mudar("modoPreparo",e.target.value)} className={input+" min-h-28"}/></label><label className="col-span-full text-xs text-slate-500">Observa&ccedil;&otilde;es<textarea value={form.observacoes||""} onChange={e=>mudar("observacoes",e.target.value)} className={input+" min-h-20"}/></label><label className="flex items-center gap-2 text-sm"><input type="checkbox" checked={Boolean(form.ativo)} onChange={e=>mudar("ativo",e.target.checked)} className="accent-[#7A1420]"/> Receita ativa para produ&ccedil;&atilde;o</label></div></Card>
  <Card className="overflow-hidden border-emerald-200 dark:border-emerald-700"><div className="border-b border-emerald-100 bg-emerald-50/70 p-4 dark:border-emerald-800 dark:bg-emerald-950/20"><h4 className="font-semibold text-emerald-900 dark:text-emerald-200">Produto final e rendimento</h4><p className="text-xs text-emerald-700 dark:text-emerald-300">Selecione o item que receber&aacute; a entrada no estoque quando a produ&ccedil;&atilde;o for conclu&iacute;da.</p></div><div className="grid gap-3 p-4 sm:grid-cols-2 lg:grid-cols-4"><label className="text-xs text-slate-500 sm:col-span-2">Produto final vinculado ao estoque<select required value={form.produtoFinalId||""} onChange={e=>escolherProdutoFinal(e.target.value)} className={input}><option value="">Selecione um produto do estoque</option>{insumos.map(i=><option key={i.id} value={i.id}>{i.cod} &middot; {i.nome} ({i.un})</option>)}</select></label><label className="text-xs text-slate-500">Rendimento da receita<input required type="number" min="0.001" step="0.001" value={form.rendimento} onChange={e=>mudar("rendimento",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Unidade do produto<input required readOnly value={form.unidadeRendimento||""} className={input+" bg-slate-50 dark:bg-slate-900"}/></label><div className="sm:col-span-2 lg:col-span-4 rounded-xl bg-slate-50 px-4 py-3 text-xs text-slate-500 dark:bg-slate-900/50">{produtoFinal ? <>Saldo atual: <strong>{n(produtoFinal.qtd).toLocaleString("pt-BR")} {produtoFinal.un}</strong>. Ao concluir a produ&ccedil;&atilde;o, os ingredientes ser&atilde;o baixados e o rendimento l&iacute;quido entrar&aacute; neste produto.</> : "Cadastre primeiro o produto em Estoque > Adicionar item, se ele ainda não existir."}</div></div></Card>
  <Card className="overflow-hidden"><div className="border-b border-slate-100 p-4 dark:border-slate-700"><h4 className="font-semibold">Consumo de ingredientes</h4><p className="text-xs text-slate-400">Custo estimado calculado: {money(custo)}</p></div><div className="grid gap-2 p-4 md:grid-cols-[1.2fr_1fr_100px_90px_auto]"><label className="text-xs text-slate-500">Item do estoque<select value={novo.insumoId} onChange={e=>escolher(e.target.value)} className={input}><option value="">Selecione um item do estoque</option>{insumos.map(i=><option key={i.id} value={i.id}>{i.nome} ({i.un})</option>)}</select></label><label className="text-xs text-slate-500">Ingrediente<input readOnly value={novo.nome} className={input+" bg-slate-50 dark:bg-slate-900"}/></label><label className="text-xs text-slate-500">Qtd.<input type="number" min="0.001" step="0.001" value={novo.quantidade} onChange={e=>setNovo(a=>({...a,quantidade:e.target.value}))} className={input}/></label><label className="text-xs text-slate-500">Un.<input readOnly value={novo.unidade} className={input+" bg-slate-50 dark:bg-slate-900"}/></label><button type="button" onClick={adicionar} className={secondary+" self-end"}><Plus size={15}/>Adicionar</button></div><div className="overflow-x-auto"><table className="w-full min-w-[560px] text-sm"><tbody>{form.itens.map((i,p)=><tr key={i.nome+"-"+p} className="border-t border-slate-100 dark:border-slate-700"><td className="px-4 py-3 font-medium">{i.nome}</td><td className="px-4 py-3 text-right">{n(i.quantidade).toLocaleString("pt-BR")} {i.unidade}</td><td className="px-4 py-3 text-right">{money(i.custoUnitario)}</td><td className="px-4 py-3 text-right"><button type="button" onClick={()=>mudar("itens",form.itens.filter((_,x)=>x!==p))} className="text-rose-600">Remover</button></td></tr>)}</tbody></table>{!form.itens.length&&<p className="p-6 text-center text-sm text-slate-400">Adicione ao menos um ingrediente.</p>}</div></Card>
  {receita?.id&&<Card className="overflow-hidden"><div className="border-b border-slate-100 p-4 dark:border-slate-700"><h4 className="font-semibold">Hist&oacute;rico desta receita</h4><p className="text-xs text-slate-400">Produ&ccedil;&otilde;es preservadas para acompanhamento e auditoria.</p></div><div className="overflow-x-auto"><table className="w-full min-w-[760px] text-sm"><thead className="border-b border-slate-100 text-left text-xs uppercase text-slate-400 dark:border-slate-700"><tr><th className="px-4 py-3">Data</th><th className="px-4 py-3">Funcion&aacute;rio</th><th className="px-4 py-3">Setor</th><th className="px-4 py-3 text-right">Quantidade</th><th className="px-4 py-3">Status</th><th className="px-4 py-3 text-right">Perda</th></tr></thead><tbody>{historico.map(i=><tr key={i.id} className="border-b border-slate-50 dark:border-slate-700/60"><td className="px-4 py-3">{date(i.dataProducao)}</td><td className="px-4 py-3">{i.funcionario?.nome||"—"}</td><td className="px-4 py-3">{i.setor||i.funcionario?.setor||"—"}</td><td className="px-4 py-3 text-right">{n(i.quantidadeProduzida).toLocaleString("pt-BR")} {i.unidade}</td><td className="px-4 py-3"><Status status={i.status}/></td><td className="px-4 py-3 text-right">{n(i.quantidadePerdida).toLocaleString("pt-BR")}</td></tr>)}</tbody></table>{!historico.length&&<p className="p-6 text-center text-sm text-slate-400">Nenhuma produ&ccedil;&atilde;o registrada para esta receita.</p>}</div></Card>}
  <div className="flex justify-end"><button disabled={salvando||!form.produtoFinalId||!form.itens.length} className={primary}>{salvando?"Salvando...":"Salvar ficha técnica"}</button></div>
 </form>;
}
function ProducaoForm({ producao, receitas, funcionarios, onSalvar, salvando, modoCozinha=false }) {
 const [form,setForm]=useState(()=>({...vazioProducao(),...producao,dataProducao:producao?.dataProducao?String(producao.dataProducao).slice(0,10):new Date().toISOString().slice(0,10),horaInicio:toDateTimeInput(producao?.horaInicio),horaFim:toDateTimeInput(producao?.horaFim),validade:producao?.validade?String(producao.validade).slice(0,10):"",quantidadeProduzida:producao?.quantidadeProduzida??"",quantidadePerdida:producao?.quantidadePerdida??""}));
 const mudar=(k,v)=>setForm(a=>({...a,[k]:v}));
 const receita=receitas.find(i=>i.id===form.receitaId);
 const bloqueado=Boolean(producao?.estoqueProcessadoEm);
 const escolherReceita=id=>{const item=receitas.find(i=>i.id===id);setForm(a=>({...a,receitaId:id,quantidadeProduzida:item?.rendimento??a.quantidadeProduzida,unidade:item?.unidadeRendimento||a.unidade,setor:item?.setorPadrao||a.setor}));};
 const enviar=e=>{
  e.preventDefault();
  const completo={...form,setor:(form.setor||receita?.setorPadrao||"Produ\u00e7\u00e3o geral").trim(),quantidadeProduzida:n(form.quantidadeProduzida),quantidadePerdida:form.quantidadePerdida===""?undefined:n(form.quantidadePerdida),dataProducao:toIsoDate(form.dataProducao),horaInicio:toIsoDateTime(form.horaInicio),horaFim:toIsoDateTime(form.horaFim),validade:toIsoDate(form.validade)};
  const body=bloqueado?{funcionarioId:form.funcionarioId,setor:completo.setor,dataProducao:completo.dataProducao,horaInicio:completo.horaInicio,horaFim:completo.horaFim,lote:form.lote,validade:completo.validade,observacoes:form.observacoes}:completo;
  onSalvar(body);
 }
 return <form onSubmit={enviar} className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">{!receitas.length&&<div className="col-span-full rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800">Nenhuma receita ativa foi encontrada. Cadastre ou ative uma ficha em Receitas de Produ&ccedil;&atilde;o.</div>}{!funcionarios.length&&<div className="col-span-full rounded-xl border border-sky-200 bg-sky-50 px-4 py-3 text-sm text-sky-800">Cadastre pelo menos um funcion&aacute;rio ativo em Usu&aacute;rios &gt; Funcion&aacute;rios para definir o respons&aacute;vel pela ordem.</div>}<label className="text-xs text-slate-500">Receita produzida<select required disabled={bloqueado} value={form.receitaId} onChange={e=>escolherReceita(e.target.value)} className={input}><option value="">Selecione uma receita ativa</option>{receitas.map(i=><option key={i.id} value={i.id}>{i.codigo} &middot; {i.nome}</option>)}</select></label><label className="text-xs text-slate-500">Funcion&aacute;rio respons&aacute;vel<select required value={form.funcionarioId} onChange={e=>mudar("funcionarioId",e.target.value)} className={input}><option value="">Selecione o funcion&aacute;rio ativo</option>{funcionarios.map(i=><option key={i.id} value={i.id}>#{i.codigo} &middot; {i.nome} ({i.setor})</option>)}</select></label><label className="text-xs text-slate-500">Setor<input required value={form.setor||receita?.setorPadrao||""} onChange={e=>mudar("setor",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Status<select disabled={bloqueado} value={form.status} onChange={e=>mudar("status",e.target.value)} className={input}><option value="EM_ANDAMENTO">Em andamento</option><option value="PAUSADA">{modoCozinha?"Aguardando":"Pausada"}</option><option value="CONCLUIDA">Conclu&iacute;da e lan&ccedil;ar estoque</option></select></label><label className="text-xs text-slate-500">Quantidade produzida<input required disabled={bloqueado} type="number" min="0.001" step="0.001" value={form.quantidadeProduzida} onChange={e=>mudar("quantidadeProduzida",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Unidade do produto<input required readOnly value={form.unidade||receita?.unidadeRendimento||""} className={input+" bg-slate-50 dark:bg-slate-900"}/></label>{receita&&<div className="col-span-full rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-xs text-emerald-800 dark:border-emerald-800 dark:bg-emerald-950/20 dark:text-emerald-200">Produto final: <strong>{receita.produtoFinal?.nome||"Não vinculado"}</strong>. Ao concluir, o sistema baixa os ingredientes proporcionalmente e adiciona a quantidade l&iacute;quida ao estoque deste produto.</div>}{bloqueado&&<div className="col-span-full rounded-xl border border-sky-200 bg-sky-50 px-4 py-3 text-xs text-sky-800">Estoque processado em {dateTime(producao.estoqueProcessadoEm)}. Quantidade, receita e perdas ficam bloqueadas para preservar a auditoria.</div>}<label className="text-xs text-slate-500">Data da produ&ccedil;&atilde;o<input required type="date" value={form.dataProducao} onChange={e=>mudar("dataProducao",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">In&iacute;cio<input type="datetime-local" value={form.horaInicio} onChange={e=>mudar("horaInicio",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">T&eacute;rmino<input type="datetime-local" value={form.horaFim} onChange={e=>mudar("horaFim",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">N&uacute;mero do lote<input value={form.lote} onChange={e=>mudar("lote",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Validade<input type="date" value={form.validade} onChange={e=>mudar("validade",e.target.value)} className={input}/></label><label className="text-xs text-slate-500">Quantidade perdida<input disabled={bloqueado} type="number" min="0" step="0.001" value={form.quantidadePerdida} onChange={e=>mudar("quantidadePerdida",e.target.value)} className={input}/></label><label className="sm:col-span-2 text-xs text-slate-500">Motivo da perda<input disabled={bloqueado} value={form.motivoPerda||""} onChange={e=>mudar("motivoPerda",e.target.value)} className={input}/></label><label className="sm:col-span-2 text-xs text-slate-500">Observa&ccedil;&otilde;es<textarea value={form.observacoes||""} onChange={e=>mudar("observacoes",e.target.value)} className={input+" min-h-20"}/></label><div className="col-span-full flex justify-end"><button disabled={salvando||!receitas.length||!funcionarios.length} className={primary}>{salvando?"Salvando...":bloqueado?"Atualizar observações":"Salvar produção"}</button></div></form>;
}
function TabelaProducoes({ producoes, editar, cancelar, pausar, continuar, perda, observacao, estornar, processarEstoque }) { return <div className="overflow-x-auto"><table className="w-full min-w-[1120px] text-sm"><thead className="border-b border-slate-100 text-left text-xs uppercase text-slate-400 dark:border-slate-700"><tr><th className="px-4 py-3">Data</th><th className="px-4 py-3">Receita</th><th className="px-4 py-3">Responsável</th><th className="px-4 py-3">Setor</th><th className="px-4 py-3 text-right">Quantidade</th><th className="px-4 py-3">Lote</th><th className="px-4 py-3">Horários</th><th className="px-4 py-3">Status</th><th className="px-4 py-3 text-right">Perda</th><th/></tr></thead><tbody>{producoes.map(i=><tr key={i.id} className="border-b border-slate-50 dark:border-slate-700/60"><td className="px-4 py-3 text-slate-500">{date(i.dataProducao)}</td><td className="px-4 py-3"><div className="font-medium">{i.receita?.nome}</div><div className="font-mono text-[11px] text-slate-400">{i.receita?.codigo}</div></td><td className="px-4 py-3"><div>{i.funcionario?.nome}</div><div className="text-xs text-slate-400">{i.funcionario?.setor}</div></td><td className="px-4 py-3">{i.setor||i.funcionario?.setor||"—"}</td><td className="px-4 py-3 text-right">{n(i.quantidadeProduzida).toLocaleString("pt-BR")} {i.unidade}</td><td className="px-4 py-3 text-slate-500">{i.lote||"—"}</td><td className="px-4 py-3 text-xs text-slate-500">{dateTime(i.horaInicio)}<br/>{i.horaFim ? "até "+dateTime(i.horaFim)+" · "+(i.tempoTotalMinutos??0)+" min" : "Sem término"}</td><td className="px-4 py-3"><Status status={i.status}/>{i.status!=="CANCELADA"&&i.estoqueProcessadoEm&&<div className="mt-1 text-[10px] font-semibold text-emerald-700">Estoque lan&ccedil;ado</div>}{i.status==="CANCELADA"&&i.estoqueProcessadoEm&&<div className="mt-1 text-[10px] font-semibold text-sky-700">Estoque estornado</div>}{i.status==="CONCLUIDA"&&!i.estoqueProcessadoEm&&<div className="mt-1 text-[10px] font-semibold text-amber-700">Estoque pendente</div>}{i.atrasada&&<div className="mt-1 text-[10px] font-semibold text-rose-600">Atrasada</div>}</td><td className="px-4 py-3 text-right">{n(i.quantidadePerdida).toLocaleString("pt-BR")}</td><td className="px-4 py-3"><div className="flex justify-end gap-1"><button onClick={()=>editar(i)} title="Editar ou visualizar" className="rounded-lg p-1.5 text-slate-500 hover:bg-slate-100 hover:text-[#7A1420]"><Pencil size={16}/></button>{i.status==="EM_ANDAMENTO"&&pausar&&<button onClick={()=>pausar(i)} title="Pausar" className="rounded-lg p-1.5 text-slate-500 hover:bg-sky-50 hover:text-sky-700"><Clock size={16}/></button>}{i.status==="PAUSADA"&&continuar&&<button onClick={()=>continuar(i)} title="Continuar" className="rounded-lg p-1.5 text-slate-500 hover:bg-emerald-50 hover:text-emerald-700"><CheckCircle2 size={16}/></button>}{i.status!=="CANCELADA"&&!i.estoqueProcessadoEm&&perda&&<button onClick={()=>perda(i)} title="Informar perda" className="rounded-lg p-1.5 text-slate-500 hover:bg-amber-50 hover:text-amber-700"><FlaskConical size={16}/></button>}{i.status!=="CANCELADA"&&observacao&&<button onClick={()=>observacao(i)} title="Adicionar observação" className="rounded-lg p-1.5 text-slate-500 hover:bg-slate-100 hover:text-[#7A1420]"><Eye size={16}/></button>}{i.status!=="CANCELADA"&&i.status!=="CONCLUIDA"&&!i.estoqueProcessadoEm&&<button onClick={()=>cancelar(i)} title="Cancelar" className="rounded-lg p-1.5 text-slate-500 hover:bg-rose-50 hover:text-rose-600"><CircleX size={16}/></button>}{i.status==="CONCLUIDA"&&!i.estoqueProcessadoEm&&processarEstoque&&<button onClick={()=>processarEstoque(i)} title="Processar estoque pendente" className="rounded-lg p-1.5 text-amber-600 hover:bg-amber-50"><RefreshCw size={16}/></button>}{i.status==="CONCLUIDA"&&estornar&&<button onClick={()=>estornar(i)} title={i.estoqueProcessadoEm?"Excluir ordem e estornar estoque":"Excluir ordem"} className="rounded-lg p-1.5 text-rose-600 hover:bg-rose-50"><Trash2 size={16}/></button>}</div></td></tr>)}</tbody></table>{!producoes.length&&<p className="p-10 text-center text-sm text-slate-400">Nenhuma produção encontrada.</p>}</div>; }

function OrdemCard({ ordem, tipo, editar, cancelar, pausar, iniciar, concluir, estornar, processarEstoque }) {
 const estoqueOk=Boolean(ordem.estoqueProcessadoEm);
 return <Card className="p-4"><div className="flex items-center justify-between gap-3"><span className="font-mono text-[11px] text-slate-400">#{ordem.id.slice(-6).toUpperCase()}</span>{tipo==="preparo"?<Clock size={15} className="text-[#7A1420]"/>:tipo==="concluida"?<CheckCircle2 size={15} className={estoqueOk?"text-emerald-500":"text-amber-500"}/>:<PauseCircle size={15} className="text-slate-400"/>}</div><h4 className="mt-2 font-semibold text-slate-900 dark:text-white">{ordem.receita?.nome||"Receita"}</h4><p className="mt-1 text-xs text-slate-500">{n(ordem.quantidadeProduzida).toLocaleString("pt-BR")} {ordem.unidade} &middot; {ordem.funcionario?.nome||"Sem respons\u00e1vel"}</p><p className="mt-1 text-[11px] text-slate-400">{ordem.lote?"Lote "+ordem.lote+" \u00b7 ":""}{ordem.setor||ordem.funcionario?.setor||"Cozinha"}</p>{tipo==="preparo"&&<div className="mt-3"><div className="h-1.5 overflow-hidden rounded-full bg-slate-100 dark:bg-slate-700"><div className="h-full w-2/3 rounded-full bg-[#7A1420]"/></div><p className="mt-1 text-[11px] text-slate-400">Produ\u00e7\u00e3o em andamento</p></div>}<div className="mt-3 flex flex-wrap gap-2"><button onClick={()=>editar(ordem)} className="rounded-lg border border-slate-200 px-3 py-1.5 text-xs text-slate-600 dark:border-slate-600 dark:text-slate-200">Detalhes</button>{tipo==="aguardando"&&<button onClick={()=>iniciar(ordem)} className="flex-1 rounded-lg bg-[#7A1420] px-3 py-1.5 text-xs font-medium text-white">Iniciar produ\u00e7\u00e3o</button>}{tipo==="preparo"&&<><button onClick={()=>pausar(ordem)} className="rounded-lg border border-sky-200 px-3 py-1.5 text-xs text-sky-700">Pausar</button><button onClick={()=>concluir(ordem)} className="flex-1 rounded-lg bg-[#7A1420] px-3 py-1.5 text-xs font-medium text-white">Concluir e movimentar estoque</button></>}{tipo!=="concluida"&&<button onClick={()=>cancelar(ordem)} className="rounded-lg border border-rose-200 px-3 py-1.5 text-xs text-rose-600">Cancelar</button>}</div>{tipo==="concluida"&&<div className="mt-3 space-y-2">{estoqueOk?<p className="text-[11px] font-medium text-emerald-600">Estoque movimentado &middot; {dateTime(ordem.estoqueProcessadoEm)}</p>:<p className="text-[11px] font-semibold text-amber-700">Estoque pendente de processamento</p>}<div className="flex flex-wrap gap-2">{!estoqueOk&&<button onClick={()=>processarEstoque(ordem)} className="inline-flex flex-1 items-center justify-center gap-1 rounded-lg border border-amber-200 px-3 py-1.5 text-xs font-medium text-amber-700"><RefreshCw size={14}/>Processar estoque</button>}<button onClick={()=>estornar(ordem)} className="inline-flex flex-1 items-center justify-center gap-1 rounded-lg border border-rose-200 px-3 py-1.5 text-xs font-medium text-rose-600"><Trash2 size={14}/>{estoqueOk?"Excluir e estornar":"Excluir ordem"}</button></div></div>}</Card>;
}

function PainelCozinha({ producoes, editar, cancelar, pausar, iniciar, concluir, estornar, processarEstoque }) {
 const hoje=new Date().toLocaleDateString("pt-BR");
 const colunas=[{key:"aguardando",label:"Aguardando",dados:producoes.filter(i=>i.status==="PAUSADA")},{key:"preparo",label:"Em preparo",dados:producoes.filter(i=>i.status==="EM_ANDAMENTO")},{key:"concluida",label:"Conclu\u00eddos hoje",dados:producoes.filter(i=>i.status==="CONCLUIDA"&&new Date(i.dataProducao).toLocaleDateString("pt-BR")===hoje)}];
 return <div className="grid gap-4 md:grid-cols-3">{colunas.map(coluna=><section key={coluna.key} className="space-y-3"><div className="flex items-center justify-between px-1"><h3 className="text-sm font-semibold text-slate-700 dark:text-slate-200">{coluna.label}</h3><span className="rounded-full bg-slate-100 px-2 py-0.5 text-xs font-semibold text-slate-600 dark:bg-slate-700 dark:text-slate-200">{coluna.dados.length}</span></div>{!coluna.dados.length&&<div className="rounded-xl border border-dashed border-slate-200 p-5 text-center text-xs text-slate-400 dark:border-slate-700">Nenhuma ordem</div>}{coluna.dados.map(ordem=><OrdemCard key={ordem.id} ordem={ordem} tipo={coluna.key} editar={editar} cancelar={cancelar} pausar={pausar} iniciar={iniciar} concluir={concluir} estornar={estornar} processarEstoque={processarEstoque}/>)}</section>)}</div>;
}
function Linha({ label, valor }) { return <div className="flex items-center justify-between border-b border-slate-100 pb-3 last:border-0 dark:border-slate-700"><span className="text-slate-500">{label}</span><strong>{valor}</strong></div>; }function PainelCadastro({ dados, filtros, mudar, categorias, abrir, duplicar, alternar, excluir, meta }) { return <Card className="overflow-hidden"><div className="flex flex-col gap-3 border-b border-slate-100 p-4 lg:flex-row dark:border-slate-700"><div className="relative min-w-0 flex-1"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input value={filtros.busca} onChange={e=>mudar("busca",e.target.value)} placeholder="Pesquisar por nome, categoria ou código..." className="w-full rounded-xl border border-slate-200 bg-white py-2.5 pl-9 pr-3 text-sm dark:border-slate-600 dark:bg-slate-800"/></div><div className="flex flex-wrap gap-2"><select value={filtros.categoria} onChange={e=>mudar("categoria",e.target.value)} className={secondary}><option value="">Categorias</option>{categorias.map(i=><option key={i} value={i}>{i}</option>)}</select><select value={filtros.status} onChange={e=>mudar("status",e.target.value)} className={secondary}><option value="ativo">Ativas</option><option value="inativo">Inativas</option><option value="todos">Todas</option></select><select value={filtros.ordenarPor} onChange={e=>mudar("ordenarPor",e.target.value)} className={secondary}><option value="nome">Ordenar: nome</option><option value="codigo">Código</option><option value="categoria">Categoria</option><option value="criadoEm">Criação</option></select></div></div><div className="overflow-x-auto"><table className="w-full min-w-[940px] text-sm"><thead className="border-b border-slate-100 text-left text-xs uppercase text-slate-400 dark:border-slate-700"><tr><th className="px-4 py-3">Código</th><th className="px-4 py-3">Receita</th><th className="px-4 py-3">Rendimento</th><th className="px-4 py-3 text-right">Custo</th><th className="px-4 py-3">Status</th><th className="px-4 py-3">Atualização</th><th/></tr></thead><tbody>{dados.map(i=><tr key={i.id} className="border-b border-slate-50 dark:border-slate-700/60"><td className="px-4 py-3 font-mono text-xs text-slate-500">{i.codigo}</td><td className="px-4 py-3"><div className="font-medium">{i.nome}</div><div className="text-xs text-slate-400">{i.categoria||"Sem categoria"} · {i._count?.itens||0} ingredientes</div></td><td className="px-4 py-3">{n(i.rendimento).toLocaleString("pt-BR")} {i.unidadeRendimento}</td><td className="px-4 py-3 text-right">{i.custoEstimado==null?"—":money(i.custoEstimado)}</td><td className="px-4 py-3"><Status ativo={i.ativo}/></td><td className="px-4 py-3 text-slate-500">{date(i.atualizadoEm)}</td><td className="px-4 py-3"><div className="flex justify-end gap-1"><button onClick={()=>abrir(i)} title="Visualizar ou editar" className="rounded-lg p-1.5 text-slate-500 hover:bg-slate-100 hover:text-[#7A1420]"><Eye size={16}/></button><button onClick={()=>duplicar(i)} title="Duplicar" className="rounded-lg p-1.5 text-slate-500 hover:bg-slate-100 hover:text-[#7A1420]"><Copy size={16}/></button><button onClick={()=>alternar(i)} title={i.ativo?"Inativar":"Ativar"} className="rounded-lg p-1.5 text-slate-500 hover:bg-slate-100 hover:text-[#7A1420]">{i.ativo?<CircleX size={16}/>:<CheckCircle2 size={16}/>}</button>{!i._count?.producoes&&<button onClick={()=>excluir(i)} title="Excluir" className="rounded-lg p-1.5 text-slate-500 hover:bg-rose-50 hover:text-rose-600"><Trash2 size={16}/></button>}</div></td></tr>)}</tbody></table>{!dados.length&&<p className="p-10 text-center text-sm text-slate-400">Nenhuma receita encontrada.</p>}</div><Paginacao meta={meta} mudar={p=>mudar("page",p)}/></Card>; }
function PainelHistorico({ producoes, filtros, mudar, receitas, funcionarios, editar, cancelar, pausar, continuar, perda, observacao, estornar, processarEstoque }) { return <Card className="overflow-hidden"><div className="flex flex-col gap-3 border-b border-slate-100 p-4 xl:flex-row dark:border-slate-700"><div className="relative min-w-0 flex-1"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input value={filtros.busca} onChange={e=>mudar("busca",e.target.value)} placeholder="Pesquisar receita, funcionário ou lote..." className="w-full rounded-xl border border-slate-200 bg-white py-2.5 pl-9 pr-3 text-sm dark:border-slate-600 dark:bg-slate-800"/></div><div className="flex flex-wrap gap-2"><select value={filtros.funcionarioId} onChange={e=>mudar("funcionarioId",e.target.value)} className={secondary}><option value="">Funcionários</option>{funcionarios.map(i=><option key={i.id} value={i.id}>{i.nome}</option>)}</select><select value={filtros.receitaId} onChange={e=>mudar("receitaId",e.target.value)} className={secondary}><option value="">Receitas</option>{receitas.map(i=><option key={i.id} value={i.id}>{i.nome}</option>)}</select><select value={filtros.status} onChange={e=>mudar("status",e.target.value)} className={secondary}><option value="">Todos os status</option><option value="EM_ANDAMENTO">Em andamento</option><option value="PAUSADA">Pausadas</option><option value="CONCLUIDA">Concluídas</option><option value="CANCELADA">Canceladas</option></select></div><Periodo filtros={filtros} mudar={mudar}/></div><TabelaProducoes producoes={producoes.data} editar={editar} cancelar={cancelar} pausar={pausar} continuar={continuar} perda={perda} observacao={observacao} estornar={estornar} processarEstoque={processarEstoque}/><Paginacao meta={producoes.meta} mudar={p=>mudar("page",p)}/></Card>; }
function PainelIndicadores({ kpis, ranking, tipo, setTipo, filtros, mudar, funcionarios, receitas, setores }) { return <><div className="flex flex-col gap-3 lg:flex-row lg:items-end lg:justify-between"><Periodo filtros={filtros} mudar={mudar}/><div className="flex flex-wrap gap-2"><select value={filtros.funcionarioId} onChange={e=>mudar("funcionarioId",e.target.value)} className={secondary}><option value="">Todos os funcionários</option>{funcionarios.map(i=><option key={i.id} value={i.id}>{i.nome}</option>)}</select><select value={filtros.setor} onChange={e=>mudar("setor",e.target.value)} className={secondary}><option value="">Todos os setores</option>{setores.map(i=><option key={i} value={i}>{i}</option>)}</select><select value={filtros.receitaId} onChange={e=>mudar("receitaId",e.target.value)} className={secondary}><option value="">Todas as receitas</option>{receitas.map(i=><option key={i.id} value={i.id}>{i.nome}</option>)}</select></div></div><div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4"><Metric label="Total de produções" value={kpis?.totalProducoes??0} hint={`${kpis?.receitasDiferentes??0} receitas diferentes`} Icon={BarChart3}/><Metric label="Quantidade total" value={n(kpis?.quantidadeTotal).toLocaleString("pt-BR")} hint="Somente não canceladas" Icon={FlaskConical}/><Metric label="Tempo médio" value={`${kpis?.tempoMedioMinutos??0} min`} hint="Produções com horários" Icon={Clock}/><Metric label="Canceladas" value={kpis?.canceladas??0} hint="Preservadas para auditoria" Icon={CircleX}/><Metric label="Perdas" value={n(kpis?.quantidadePerdida).toLocaleString("pt-BR")} hint={`${kpis?.producoesComPerdas??0} produções com perda`} Icon={FlaskConical}/><Metric label="Atrasadas" value={kpis?.producoesAtrasadas??kpis?.atrasadas??0} hint="Acima do tempo estimado" Icon={Clock}/></div><div className="grid gap-4 xl:grid-cols-[1.45fr_1fr]"><Card className="overflow-hidden"><div className="flex items-center justify-between border-b border-slate-100 p-4 dark:border-slate-700"><div><h3 className="font-semibold">Ranking de funcionários</h3><p className="text-xs text-slate-400">Cancelamentos não entram na classificação.</p></div><select value={tipo} onChange={e=>setTipo(e.target.value)} className={secondary}><option value="registros">Por nº de produções</option><option value="volume">Por quantidade</option></select></div><div className="overflow-x-auto"><table className="w-full min-w-[700px] text-sm"><thead className="border-b border-slate-100 text-left text-xs uppercase text-slate-400 dark:border-slate-700"><tr><th className="px-4 py-3">#</th><th className="px-4 py-3">Funcionário</th><th className="px-4 py-3 text-right">Produções</th><th className="px-4 py-3 text-right">Quantidade</th><th className="px-4 py-3 text-right">Receitas</th><th className="px-4 py-3 text-right">Participação</th></tr></thead><tbody>{ranking.map(i=><tr key={i.funcionario.id} className="border-b border-slate-50 dark:border-slate-700/60"><td className="px-4 py-3 font-semibold text-[#7A1420]">{i.posicao}º</td><td className="px-4 py-3"><div className="font-medium">{i.funcionario.nome}</div><div className="text-xs text-slate-400">{i.funcionario.setor}</div></td><td className="px-4 py-3 text-right">{i.producoes}</td><td className="px-4 py-3 text-right">{n(i.quantidadeTotal).toLocaleString("pt-BR")}</td><td className="px-4 py-3 text-right">{i.receitasDiferentes}</td><td className="px-4 py-3 text-right"><div className="ml-auto h-2 w-20 overflow-hidden rounded-full bg-slate-100"><div className="h-full bg-[#7A1420]" style={{width:`${Math.min(100,i.participacao)}%`}}/></div><span className="text-xs text-slate-500">{i.participacao}%</span></td></tr>)}</tbody></table>{!ranking.length&&<p className="p-10 text-center text-sm text-slate-400">Sem produções válidas no período selecionado.</p>}</div></Card><Card className="p-5"><h3 className="font-semibold">Resumo do período</h3><div className="mt-4 space-y-3 text-sm"><Linha label="Concluídas" valor={kpis?.concluidas??0}/><Linha label="Em andamento" valor={kpis?.emAndamento??0}/><Linha label="Produções hoje" valor={kpis?.producoesHoje??0}/><Linha label="Produções na semana" valor={kpis?.producoesSemana??0}/><Linha label="Produções no mês" valor={kpis?.producoesMes??0}/><Linha label="Mais registros" valor={kpis?.funcionarioMaisProducoes?.nome||"—"}/><Linha label="Maior volume" valor={kpis?.funcionarioMaiorQuantidade?.nome||"—"}/><Linha label="Receita mais produzida" valor={kpis?.receitaMaisProduzida?.nome||"—"}/></div></Card></div></>; }export default function ReceitasProducao({ modoCozinha = false, onEstoqueAlterado = async () => {} }) {
 const [aba,setAba]=useState(modoCozinha ? "producao" : "cadastro"),[receitas,setReceitas]=useState({data:[],meta:null}),[ativas,setAtivas]=useState([]),[funcionarios,setFuncionarios]=useState([]),[insumos,setInsumos]=useState([]),[producoes,setProducoes]=useState({data:[],meta:null}),[kpis,setKpis]=useState(null),[ranking,setRanking]=useState([]),[tipo,setTipo]=useState("registros"),[historicoReceita,setHistoricoReceita]=useState([]),[modal,setModal]=useState(null),[erro,setErro]=useState(""),[mensagem,setMensagem]=useState(""),[salvando,setSalvando]=useState(false);
 const [fr,setFr]=useState({busca:"",categoria:"",status:"ativo",page:1,limit:10,ordenarPor:"nome",direcao:"asc"});
 const [fp,setFp]=useState({busca:"",funcionarioId:"",receitaId:"",status:"",periodo:"todos",dataInicio:"",dataFim:"",page:1,limit:50,ordenarPor:"dataProducao",direcao:"desc"});
 const [fi,setFi]=useState({periodo:"mes",dataInicio:"",dataFim:"",funcionarioId:"",receitaId:"",setor:"",status:""});
 const muda=(set,k,v)=>set(a=>({...a,[k]:v,page:k==="page"?v:1}));
 const base=async()=>{if(!api.enabled)return;try{const [lista,rs,fs,es]=await Promise.all([api.getReceitas(fr),api.getReceitasAtivas(),api.getFuncionariosAtivos(),api.getInsumos()]);setReceitas(lista);setAtivas(rs);setFuncionarios(fs);setInsumos(es.data||[]);}catch(e){setErro(falha(e));}};
 const historico=async()=>{if(!api.enabled)return;try{setProducoes(await api.getProducoesReceitas(fp));}catch(e){setErro(falha(e));}};
 const analise=async()=>{if(!api.enabled)return;try{const [a,b]=await Promise.all([api.getIndicadoresProducao(fi),api.getRankingProducao({...fi,tipo})]);setKpis(a);setRanking(b);}catch(e){setErro(falha(e));}};
 const aposMovimentacao=async()=>{await Promise.all([historico(),analise(),base(),Promise.resolve(onEstoqueAlterado?.())]);};
 useEffect(()=>{base();},[JSON.stringify(fr)]);
 useEffect(()=>{historico();},[JSON.stringify(fp)]);
 useEffect(()=>{analise();},[JSON.stringify(fi),tipo]);
 const categorias=useMemo(()=>[...new Set(receitas.data.map(i=>i.categoria).filter(Boolean))],[receitas]);
 const setores=useMemo(()=>[...new Set(funcionarios.map(i=>i.setor).filter(Boolean))],[funcionarios]);
 const abrirReceita=async r=>{try{setModal({tipo:"receita",carregando:true});const [receita,historico]=await Promise.all([api.getReceita(r.id),api.getProducoesReceitas({receitaId:r.id,limit:50,ordenarPor:"dataProducao",direcao:"desc"})]);setHistoricoReceita(historico.data||[]);setModal({tipo:"receita",receita});}catch(e){setErro(falha(e));setModal(null);}};
 const salvarReceita=async body=>{setSalvando(true);setMensagem("");try{modal?.receita?.id?await api.atualizarReceita(modal.receita.id,body):await api.cadastrarReceita(body);setModal(null);setAba("cadastro");setMensagem("Ficha t\u00e9cnica salva.");await base();}catch(e){setErro(falha(e));}finally{setSalvando(false);}};
 const salvarProducao=async body=>{setSalvando(true);setMensagem("");try{const salva=modal?.producao?.id?await api.atualizarProducaoReceita(modal.producao.id,body):await api.cadastrarProducaoReceita(body);setModal(null);setAba("producao");setMensagem(salva.estoqueProcessadoEm?"Ordem salva e estoque movimentado.":"Ordem de produ\u00e7\u00e3o salva.");await aposMovimentacao();}catch(e){setErro(falha(e));}finally{setSalvando(false);}};
 const duplicar=async r=>{try{await api.duplicarReceita(r.id);setMensagem("Receita duplicada. Revise a ficha antes de utiliz\u00e1-la.");await base();}catch(e){setErro(falha(e));}};
 const alternar=async r=>{try{await api.atualizarReceita(r.id,{ativo:!r.ativo});await base();}catch(e){setErro(falha(e));}};
 const excluir=async r=>{if(!window.confirm(`Excluir definitivamente a receita "${r.nome}"?`))return;try{await api.excluirReceita(r.id);setMensagem("Receita exclu\u00edda.");await base();}catch(e){setErro(falha(e));}};
 const editarProducao=async p=>{try{setModal({tipo:"producao",producao:await api.getProducaoReceita(p.id)});}catch(e){setErro(falha(e));}};
 const cancelar=async p=>{const motivo=window.prompt("Informe o motivo do cancelamento:");if(!motivo)return;try{await api.cancelarProducaoReceita(p.id,motivo);setMensagem("Ordem cancelada sem movimentar o estoque.");await Promise.all([historico(),analise()]);}catch(e){setErro(falha(e));}};
 const pausar=async p=>{try{await api.pausarProducaoReceita(p.id);await Promise.all([historico(),analise()]);}catch(e){setErro(falha(e));}};
 const continuar=async p=>{try{await api.continuarProducaoReceita(p.id);await Promise.all([historico(),analise()]);}catch(e){setErro(falha(e));}};
 const concluir=async p=>{if(!window.confirm("Concluir esta ordem e movimentar o estoque agora?"))return;setMensagem("");try{const concluida=await api.atualizarProducaoReceita(p.id,{status:"CONCLUIDA",horaFim:new Date().toISOString()});if(!concluida.estoqueProcessadoEm)throw new Error("A ordem foi conclu\u00edda, mas o estoque n\u00e3o confirmou o processamento.");setMensagem("Ordem conclu\u00edda: insumos baixados e produto final adicionado.");await aposMovimentacao();}catch(e){setErro(falha(e));}};
 const processarEstoque=async p=>{if(!window.confirm("Processar agora os insumos e o produto final desta ordem conclu\u00edda?"))return;setMensagem("");try{const processada=await api.processarEstoqueProducao(p.id);if(!processada.estoqueProcessadoEm)throw new Error("O estoque n\u00e3o confirmou o processamento desta ordem.");setMensagem("Estoque processado: insumos baixados e produto final adicionado.");await aposMovimentacao();}catch(e){setErro(falha(e));}};
 const estornar=async p=>{const estoqueMovimentado=Boolean(p.estoqueProcessadoEm);if(!window.confirm(estoqueMovimentado?"Excluir esta ordem conclu\u00edda, devolver os insumos e retirar o produto final do estoque?":"Excluir esta ordem conclu\u00edda sem movimenta\u00e7\u00e3o de estoque?"))return;const motivo=window.prompt("Informe o motivo do erro na ordem:");if(!motivo)return;setMensagem("");try{await api.estornarProducaoReceita(p.id,motivo);setMensagem(estoqueMovimentado?"Ordem exclu\u00edda e estoque estornado com sucesso.":"Ordem exclu\u00edda. Nenhum estoque havia sido movimentado.");await aposMovimentacao();}catch(e){setErro(falha(e));}};
 const perda=async p=>{const quantidade=window.prompt("Quantidade perdida:",String(p.quantidadePerdida||""));if(quantidade===null)return;const motivo=window.prompt("Motivo da perda:");if(!motivo)return;try{await api.informarPerdaProducao(p.id,{quantidadePerdida:n(quantidade),motivo});await Promise.all([historico(),analise()]);}catch(e){setErro(falha(e));}};
 const observacao=async p=>{const texto=window.prompt("Observa\u00e7\u00e3o da produ\u00e7\u00e3o:");if(!texto)return;try{await api.adicionarObservacaoProducao(p.id,texto);await historico();}catch(e){setErro(falha(e));}};
 const tabs=modoCozinha ? [["producao","Ordens de Produ\u00e7\u00e3o",Clock],["historico","Hist\u00f3rico de Produ\u00e7\u00e3o",History],["indicadores","Indicadores e Ranking",Trophy]] : [["cadastro","Cadastro de Receitas",FlaskConical],["nova","Nova Receita",Plus],["producao","Ordens de Produ\u00e7\u00e3o",Clock],["historico","Hist\u00f3rico de Produ\u00e7\u00e3o",History],["indicadores","Indicadores e Ranking",Trophy]];
 if(!api.enabled)return <Card className="p-6"><h2 className="font-semibold">{modoCozinha ? "Cozinha / Preparo" : "Receitas de Produ\u00e7\u00e3o"}</h2><p className="mt-2 text-sm text-slate-500">Configure a API do ERP para usar este m&oacute;dulo persistente.</p></Card>;
 return <div className="space-y-5">
  <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between"><div><h2 className="text-xl font-semibold text-slate-900 dark:text-white">{modoCozinha ? "Cozinha / Preparo" : "Receitas de Produ\u00e7\u00e3o"}</h2><p className="mt-1 text-sm text-slate-500">{modoCozinha ? producoes.data.filter(i=>i.status==="EM_ANDAMENTO"||i.status==="PAUSADA").length+" ordens abertas \u00b7 baixa autom\u00e1tica ao concluir" : "Fichas t\u00e9cnicas e ordens de produ\u00e7\u00e3o com estoque integrado."}</p></div>{aba==="producao"&&<button onClick={()=>setModal({tipo:"producao",producao:{status:"PAUSADA"}})} className={primary}><Plus size={16}/>Nova ordem de produ&ccedil;&atilde;o</button>}</div>
  {erro&&<div className="flex items-center justify-between rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-800"><span>{erro}</span><button onClick={()=>setErro("")}><X size={16}/></button></div>}
  {mensagem&&<div className="flex items-center justify-between rounded-xl border border-emerald-200 bg-emerald-50 px-4 py-3 text-sm text-emerald-800"><span>{mensagem}</span><button onClick={()=>setMensagem("")}><X size={16}/></button></div>}
  <div className="overflow-x-auto border-b border-slate-200 dark:border-slate-700"><div className="flex min-w-max gap-1">{tabs.map(([k,t,Icon])=><button key={k} onClick={()=>{setAba(k);if(k==="nova")setModal({tipo:"receita",receita:null});}} className={`inline-flex items-center gap-2 border-b-2 px-4 py-3 text-sm font-medium ${aba===k?"border-[#7A1420] text-[#7A1420]":"border-transparent text-slate-500"}`}><Icon size={16}/>{t}</button>)}</div></div>
  {(aba==="cadastro"||aba==="nova")&&<PainelCadastro dados={receitas.data} filtros={fr} mudar={(k,v)=>muda(setFr,k,v)} categorias={categorias} abrir={abrirReceita} duplicar={duplicar} alternar={alternar} excluir={excluir} meta={receitas.meta}/>}
  {aba==="producao"&&<PainelCozinha producoes={producoes.data} editar={editarProducao} cancelar={cancelar} pausar={pausar} iniciar={continuar} concluir={concluir} estornar={estornar} processarEstoque={processarEstoque}/>}
  {aba==="historico"&&<PainelHistorico producoes={producoes} filtros={fp} mudar={(k,v)=>muda(setFp,k,v)} receitas={ativas} funcionarios={funcionarios} editar={editarProducao} cancelar={cancelar} pausar={pausar} continuar={continuar} perda={perda} observacao={observacao} estornar={estornar} processarEstoque={processarEstoque}/>}
  {aba==="indicadores"&&<PainelIndicadores kpis={kpis} ranking={ranking} tipo={tipo} setTipo={setTipo} filtros={fi} mudar={(k,v)=>muda(setFi,k,v)} funcionarios={funcionarios} receitas={ativas} setores={setores}/>}
  {modal?.tipo==="receita"&&<Modal titulo={modal.carregando?"Carregando ficha...":modal.receita?.id?"Editar ficha t\u00e9cnica":"Nova receita"} onClose={()=>{setModal(null);setHistoricoReceita([]);if(aba==="nova")setAba("cadastro");}}>{modal.carregando?<p className="p-8 text-center text-sm text-slate-400">Carregando...</p>:<ReceitaForm receita={modal.receita} insumos={insumos} historico={historicoReceita} onSalvar={salvarReceita} salvando={salvando}/>}</Modal>}
  {modal?.tipo==="producao"&&<Modal titulo={modal.producao?.id?"Editar ordem de produ\u00e7\u00e3o":"Nova ordem de produ\u00e7\u00e3o"} onClose={()=>setModal(null)}><ProducaoForm producao={modal.producao} receitas={ativas} funcionarios={funcionarios} onSalvar={salvarProducao} salvando={salvando} modoCozinha/></Modal>}
 </div>;
}
